-- Veyn: hospitals directory as a real database table, so admin can apply
-- secretary-submitted contact suggestions (see migration_48_contact_suggestions.sql)
-- directly instead of just marking them applied as a record. Replaces the
-- static account/hospitals-data.js (297 entries), which is deleted once
-- every page that read it has been switched over to querying this table.
-- gp-practices.json (15,574 rows, a bulk NHS import) is intentionally NOT
-- migrated — GP suggestions stay a manual "admin edits the file" review.
-- Run this in the Supabase SQL editor.

create table hospitals (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  area text,
  town text,
  type text,
  contact text,
  website text,
  specialties text,
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index hospitals_name_idx on hospitals (lower(name));

alter table hospitals enable row level security;

create policy "Hospitals are publicly readable"
  on hospitals for select using (true);

create policy "Admins can insert hospitals"
  on hospitals for insert with check (is_admin());

create policy "Admins can update hospitals"
  on hospitals for update using (is_admin());

create policy "Admins can delete hospitals"
  on hospitals for delete using (is_admin());

-- One-time seed from account/hospitals-data.js (297 rows), generated
-- programmatically from the file, not hand-typed.
